code = """import json

data = locals()['var_function-call-10434587063476511408']
cleaned_data = []

keywords = [" specializes", " provides", " is ", " harnesses", ", based in"]

for item in data:
    desc = item['Company Name']
    # Find the earliest occurrence of any keyword
    end_idx = len(desc)
    for kw in keywords:
        idx = desc.find(kw)
        if idx != -1 and idx < end_idx:
            end_idx = idx
    
    name = desc[:end_idx].strip()
    # Remove trailing commas or periods if any (unlikely after split but good practice)
    if name.endswith(','):
        name = name[:-1]
    
    cleaned_data.append({
        "Company Name": name,
        "Average Daily Volume 2008": item['Average Daily Volume (2008)']
    })

print('__RESULT__:')
print(json.dumps(cleaned_data))"""

